import{_ as l,o,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"💡 光通訊追蹤日誌 — 2026年5月24日（週日）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-24.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-24.md"}'),a={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-24.md"};function n(e,t,s,d,c,h){return o(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="💡-光通訊追蹤日誌-—-2026年5月24日-週日" tabindex="-1">💡 光通訊追蹤日誌 — 2026年5月24日（週日） <a class="header-anchor" href="#💡-光通訊追蹤日誌-—-2026年5月24日-週日" aria-label="Permalink to &quot;💡 光通訊追蹤日誌 — 2026年5月24日（週日）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 09:20 (2026-05-24) <strong>敘事錨點</strong>：🟢 OFC 2026成果發酵中 — CPO技術全面推進，台灣供應鏈訂單能見度極佳</p></blockquote><hr><h2 id="🔴-即時指標-4項" tabindex="-1">🔴 即時指標（4項） <a class="header-anchor" href="#🔴-即時指標-4項" aria-label="Permalink to &quot;🔴 即時指標（4項）&quot;">​</a></h2><h3 id="第1項-輝達-nvidia-cpo-silicon-photonics" tabindex="-1">第1項：輝達（NVIDIA）CPO/Silicon Photonics <a class="header-anchor" href="#第1項-輝達-nvidia-cpo-silicon-photonics" aria-label="Permalink to &quot;第1項：輝達（NVIDIA）CPO/Silicon Photonics&quot;">​</a></h3><ul><li><strong>狀態</strong>：🟢 持續推進 — CPO為2026核心戰略</li><li><strong>關鍵動態</strong>： <ul><li>NVIDIA推出CPO產品線：<strong>Quantum-X Photonics InfiniBand交換器</strong> + <strong>Spectrum-X Photonics Ethernet交換器</strong></li><li>1.6T矽光子光學引擎直接整合至交換器</li><li>NVL576系統預計約一年內部署CPO（2027）</li><li><strong>投資佈局</strong>：$20億入股Coherent + Lumentum，擴大與Corning合作</li><li>Micro Ring Modulator矽光子引擎：<strong>200Gbps PAM4/波長</strong>，超低密度</li></ul></li><li><strong>來源</strong>：NVIDIA Developer Blog, IDTechEx, Medium (Beth Kindig)</li></ul><h3 id="第2項-博通-broadcom-cpo技術" tabindex="-1">第2項：博通（Broadcom）CPO技術 <a class="header-anchor" href="#第2項-博通-broadcom-cpo技術" aria-label="Permalink to &quot;第2項：博通（Broadcom）CPO技術&quot;">​</a></h3><ul><li><strong>狀態</strong>：🟢 持續推進 — 第四代CPO開發中</li><li><strong>關鍵動態</strong>： <ul><li>第四代CPO產品：<strong>每通道頻寬較第三代Tomahawk 6 Davisson翻倍</strong></li><li>Tomahawk 6已開始出貨，第四代聚焦AI資料中心</li><li>採用TSMC先進製程 + 封裝技術</li><li>Cisco, Broadcom, NVIDIA在OFC 2026均展示下一代CPO解決方案</li></ul></li><li><strong>OFC 2026重點</strong>：Meta分享CPO在大規模AI網路中的可靠性數據，驗證商用可行性</li><li><strong>來源</strong>：IDTechEx, PanewsLab, FS.com (OFC 2026 Recap)</li></ul><h3 id="第3項-台積電-tsmc-矽光子-先進封裝" tabindex="-1">第3項：台積電（TSMC）矽光子/先進封裝 <a class="header-anchor" href="#第3項-台積電-tsmc-矽光子-先進封裝" aria-label="Permalink to &quot;第3項：台積電（TSMC）矽光子/先進封裝&quot;">​</a></h3><ul><li><strong>狀態</strong>：🟢 持續推進 — COUPE on Substrate 2H26量產</li><li><strong>關鍵動態</strong>： <ul><li>TSMC COUPE平台：NVIDIA + Broadcom共同採用</li><li>SoIC-X 3D封裝技術整合光學引擎</li><li><strong>重大進展</strong>：2H26「COUPE on Substrate」方案量產</li><li>Q1 2026財報：營收NT$1.13兆（+35% YoY），淨利NT$5,725億（+58% YoY）</li><li>A13次世代製程發布，資本支出上調至$52-56B高檔</li></ul></li><li><strong>來源</strong>：TrendForce (2026-05-18), Mitsui MGSSI Report, MarketBeat (2026-05-21)</li></ul><h3 id="第4項-csp資本支出-msft-googl-amzn-meta" tabindex="-1">第4項：CSP資本支出（MSFT/GOOGL/AMZN/META） <a class="header-anchor" href="#第4項-csp資本支出-msft-googl-amzn-meta" aria-label="Permalink to &quot;第4項：CSP資本支出（MSFT/GOOGL/AMZN/META）&quot;">​</a></h3><ul><li><strong>狀態</strong>：🟢 持續擴張 — AI資本支出維持高檔</li><li><strong>關鍵動態</strong>： <ul><li>全球光收發模組出貨量：2023年2,650萬組 → 2026年預估<strong>9,200萬組</strong>（3倍成長）</li><li>CPO滲透率預估2030年超過<strong>35%</strong>（AI資料中心）</li><li>Meta在OFC 2026分享CPO可靠性和效率數據</li><li>CPO市場預估2036年超**$200億**，CAGR <strong>37%</strong>（2026-2036）</li></ul></li><li><strong>來源</strong>：TrendForce, IDTechEx, FS.com (OFC 2026)</li></ul><hr><h2 id="🟡-新聞亮點-ofc-2026後續效應" tabindex="-1">🟡 新聞亮點（OFC 2026後續效應） <a class="header-anchor" href="#🟡-新聞亮點-ofc-2026後續效應" aria-label="Permalink to &quot;🟡 新聞亮點（OFC 2026後續效應）&quot;">​</a></h2><h3 id="📢-ofc-2026重大產業進展-持續發酵中" tabindex="-1">📢 OFC 2026重大產業進展（持續發酵中） <a class="header-anchor" href="#📢-ofc-2026重大產業進展-持續發酵中" aria-label="Permalink to &quot;📢 OFC 2026重大產業進展（持續發酵中）&quot;">​</a></h3><ol><li><p><strong>GlobalFoundries SCALE光学模组方案发布</strong></p><ul><li>基於硅光子技術的WDM雙向傳輸方案</li><li>兼容OCI MSA標準，針對現代AI資料中心設計</li><li>來源：dqindia.com (2026-05)</li></ul></li><li><p><strong>Samsung Foundry 加速硅光子布局</strong></p><ul><li>已取得主要光通訊模組供應商的訂單</li><li>2H26大規模生產規劃</li><li>目標2029年推出turnkey CPO服務</li><li>來源：TrendForce (2026-05-01)</li></ul></li><li><p><strong>Coherent OFC 2026展出6.4T socket-based CPO</strong></p><ul><li>業界首個400G lane on silicon photonics</li><li>展示VCSEL-based、傳統SiPh+CW laser、InP-based CPO tile多平台策略</li><li>來源：FS.com (OFC 2026 Recap)</li></ul></li><li><p><strong>Hollow-Core Fiber (HCF) 工業化進展</strong></p><ul><li>從概念走向商業化</li><li>低色散、低損耗、低非線性、高頻寬</li><li>適用於新一代區域和長距離系統</li><li>來源：yieldwerx.com (2026-05)</li></ul></li><li><p><strong>ITU-T ION-2030倡议启动</strong></p><ul><li>&quot;International Optical Networks toward 2030 and Beyond&quot;</li><li>涵蓋AI優化資料中心和AI增強寬頻網路</li><li>來源：institutionofelectronics.ac.uk (2026-05)</li></ul></li></ol><hr><h2 id="🟡-台灣供應鏈列表-強制每日檢查" tabindex="-1">🟡 台灣供應鏈列表（強制每日檢查） <a class="header-anchor" href="#🟡-台灣供應鏈列表-強制每日檢查" aria-label="Permalink to &quot;🟡 台灣供應鏈列表（強制每日檢查）&quot;">​</a></h2><h3 id="聯亞-3081-—-🟢-強勁" tabindex="-1">聯亞 (3081) — 🟢 強勁 <a class="header-anchor" href="#聯亞-3081-—-🟢-強勁" aria-label="Permalink to &quot;聯亞 (3081) — 🟢 強勁&quot;">​</a></h3><ul><li><strong>4月營收</strong>：新台幣3.95億元（+115.38% YoY，連續5個月創歷史新高）</li><li><strong>訂單能見度</strong>：延伸至2028年，部分客戶看到2030年</li><li><strong>2026展望</strong>：新增1家大型美系雲端客戶 + 3-4家模組客戶</li></ul><h3 id="光聖-6442-—-🟢-高成長" tabindex="-1">光聖 (6442) — 🟢 高成長 <a class="header-anchor" href="#光聖-6442-—-🟢-高成長" aria-label="Permalink to &quot;光聖 (6442) — 🟢 高成長&quot;">​</a></h3><ul><li><strong>3月稅後淨利</strong>：新台幣3.12億元（+200% YoY，EPS $4.02）</li><li><strong>TPU供應鏈</strong>：佔有重要地位</li><li><strong>馬來西亞據點</strong> + <strong>菲律賓新廠2026投產</strong></li></ul><h3 id="上詮-3363-—-🟡-驗證中" tabindex="-1">上詮 (3363) — 🟡 驗證中 <a class="header-anchor" href="#上詮-3363-—-🟡-驗證中" aria-label="Permalink to &quot;上詮 (3363) — 🟡 驗證中&quot;">​</a></h3><ul><li><strong>4月股價</strong>：$1,065（反映2028-2029預期）</li><li><strong>Q1財報</strong>：虧損$1.07億（EPS -$0.98）</li><li><strong>台積電FAU獨家供應商</strong>，矽光子產品通過驗證試出貨</li></ul><h3 id="智邦-2345-—-🟢-創新高" tabindex="-1">智邦 (2345) — 🟢 創新高 <a class="header-anchor" href="#智邦-2345-—-🟢-創新高" aria-label="Permalink to &quot;智邦 (2345) — 🟢 創新高&quot;">​</a></h3><ul><li><strong>4月營收</strong>：新台幣273.6億元（+9.4% MoM, +53.9% YoY，創歷史新高）</li><li><strong>前4月累計</strong>：$974.81億（+61% YoY，創歷史新高）</li><li><strong>外資目標價</strong>：上看$3,222</li></ul><hr><h2 id="🔵-產業趨勢摘要表" tabindex="-1">🔵 產業趨勢摘要表 <a class="header-anchor" href="#🔵-產業趨勢摘要表" aria-label="Permalink to &quot;🔵 產業趨勢摘要表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>光進銅進</td><td>🟢 確立</td><td>AI算力需求爆增，傳統電信號傳輸瓶頸</td></tr><tr><td>2026商轉元年</td><td>🟢 確認</td><td>NVIDIA定調矽光子2026為商轉元年</td></tr><tr><td>CPO滲透率</td><td>🟢 增長</td><td>預估2030年超過35%（AI資料中心）</td></tr><tr><td>OCI-MSA</td><td>🟢 推進</td><td>開放光學合作持續擴展</td></tr><tr><td>HCF工業化</td><td>🟢 新趨勢</td><td>Hollow-Core Fiber從概念走向商業化</td></tr><tr><td>Samsung Foundry入場</td><td>🟢 新變數</td><td>2H26量產，2029 turnkey CPO服務</td></tr><tr><td>東南亞產能外包</td><td>🟢 加速</td><td>美系大廠將產能移至東南亞，台灣業者受益</td></tr><tr><td>AMD在台擴產</td><td>🟢 利好</td><td>AMD宣布&gt;$100億投資台灣半導體，2nm EPYC Venice</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>FS.com (2026-05): OFC 2026 Recap — Key Innovations Driving Optical Networking Forward</li><li>TrendForce (2026-05-01): Samsung Foundry獲光學模組訂單，加速硅光子發展</li><li>YieldWerx (2026-05): Photonics &amp; Optical I/O Trends &amp; Challenges</li><li>Institution of Electronics (2026-05): Where CPO Technology Stands in 2026</li><li>dqindia.com (2026-05): GlobalFoundries SCALE Optical Module Solution</li><li>Marvell.com (2026): Why Scale-up AI Networks Demand Scalable Optical Test</li><li>TSMC Q1 2026 Earnings Release (2026-05): Revenue NT$1.13T (+35% YoY)</li><li>TechNews (2026-05): 台灣光通訊供應鏈動態</li><li>CMoney (2026-05): 聯亞、光聖、上詮、智邦財務數據</li><li>PanewsLab (2026): Broadcom CPO Strategy Analysis</li></ol>',32)])])}const C=l(a,[["render",n]]);export{u as __pageData,C as default};
